// === Nustatome laiko ráéƒius ===
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);
const tomorrowStart = new Date(todayStart.getTime() + 24 * 60 * 60 * 1000);
const tomorrowEnd = new Date(todayEnd.getTime() + 24 * 60 * 60 * 1000);

let totalSolarTomorrowKWh = 0;
let totalSolarTodayKWh = 0;
let solarForecastTodayArray = [];
let solarForecastTomorrowArray = []; // [2.3.6]

// === Apdorojame duomenis ===
for (var i = 0; i < forecastArray.length; i++) {
    var record = forecastArray[i];
    var recordTimestamp = record[0];
    var recordValueWh = record[1];

    // é iandienos prognozá
    if (recordTimestamp >= todayStart.getTime() && recordTimestamp <= todayEnd.getTime()) {
        totalSolarTodayKWh += recordValueWh / 1000;
        solarForecastTodayArray.push([recordTimestamp, recordValueWh]);
    }
    // Rytojaus prognozá
    else if (recordTimestamp >= tomorrowStart.getTime() && recordTimestamp <= tomorrowEnd.getTime()) {
        totalSolarTomorrowKWh += recordValueWh / 1000;
        solarForecastTomorrowArray.push([recordTimestamp, recordValueWh]); // [2.3.6]
    }
}

// === Nustatome, ar rytojus bus debesuotas ===
