let netEnergyForecast_18_19_Wh = flow.get("netEnergyForecast_18_19_Wh") || 9999;

// [1.7.8] avgCorrectionFactor ã paskutinié° 3 valandé° vidurkis
var dailyFactors = flow.get("dailyCorrectionFactors") || [];
var recentFactors = dailyFactors.slice(-3);
var avgCorrectionFactor = recentFactors.length > 0
    ? recentFactors.reduce(function(a, b) { return a + b; }, 0) / recentFactors.length
    : correctionFactor;

// [1.7.7] MPPT throttlingo kintamieji
var mppt1W = flow.get("MPPT1W") || 0;
