// === 2. KONSTANTOS IR SISTEMOS SPECIFIKACIJOS ===
const TOTAL_BATTERY_CAPACITY_KWH = 72.28;
const SUNRISE_GENERATION_STARTS_HOUR = 9;
const UNACCOUNTED_LOSSES_WATTS = 130;
const MAX_BATTERY_CHARGE_RATE_DURING_PEAK_ADJUSTABLE_BY_FORECAST = 5000;
const EARLY_MORNING_DISCHARGE_START_HOUR = 6;
const EARLY_MORNING_DISCHARGE_END_HOUR = 9;
const TARGET_EXPORT_POWER_DURING_MORNING_DISCHARGE = 3000;
const MINIMUM_EXPORT_THRESHOLD_W = 400;
const CHARGE_AGGRESSIVENESS_FACTOR = (currentMonth >= 8 || currentMonth <= 2) ? 1.5 : 1.25;
const ABSORPTION_DURATION_HOURS = 1.5;
const MAX_VOLTAGE = 56.8;
const ABSORPTION_SURPLUS_THRESHOLD_W = 2000;

// === 3. KODO áÛVYKDYMAS ===
let actualMomentarySurplus = TotalMPPTOutput - ACC - DCW - UNACCOUNTED_LOSSES_WATTS;
let earlyMorningDischargeActive = false;
let exportAmount = 0;
const isCloudyDayDetermined = (SolarTotalForecastToday < dayThreshold);
const isSunnyDayDetermined = !isCloudyDayDetermined;

// [1.7.8] adjustedBuffer naudoja avgCorrectionFactor
let adjustedBuffer = ForecasterBufferkWh * avgCorrectionFactor;
debug.adjustedBuffer = adjustedBuffer;

let requiredDischargeKWh = Math.max(0, ForecasterBufferkWh - BattPot);
let targetDischargeSOC = SOC - (requiredDischargeKWh / TOTAL_BATTERY_CAPACITY_KWH * 100);
debug.targetDischargeSOC = targetDischargeSOC;

// === PAGRINDINá LOGIKA ===
let effectiveDayIsSunny = isSunnyDayDetermined;
debug.initialDayType = isCloudyDayDetermined ? "Cloudy" : "Sunny";
// CloudyãSunny naudoja momentiná₤ correctionFactor
if (currentHour >= 12 && isCloudyDayDetermined && correctionFactor > 1.5
    && (flow.get("SolarTodayRemaining") || 0) > BattPot) {
    effectiveDayIsSunny = true;
}
debug.effectiveDayType = effectiveDayIsSunny ? "Sunny" : "Cloudy";
debug.dayTypeSwitched = debug.initialDayType !== debug.effectiveDayType;

const absorptionActive = flow.get("absorptionPhaseActive") || false;
const absorptionEndTime = flow.get("absorptionEndTime") || 0;
let inAbsorptionPhase = false;

if (absorptionActive && nowMs < absorptionEndTime) {
    debug.mainLogicBranch = "Absorption Phase Active";
    inAbsorptionPhase = true;

    if (mpptThrottling || throttleExport > 0) {
        reservedPowerLimit = Math.max(0, actualMomentarySurplus - throttleExport);
        debug.chargeMode = mpptThrottling
            ? "Absorption (MPPT Throttling Relief)"
            : "Absorption (Throttle Reducing)";
    } else {
        reservedPowerLimit = 18000;
        exportAmount = 0;
        debug.chargeMode = "Absorption";
    }
} else if (absorptionActive) {
    flow.set("absorptionPhaseActive", false);
}

if (inAbsorptionPhase) {
} else if (DC >= MAX_VOLTAGE) {
    reservedPowerLimit = 0;
    debug.mainLogicBranch = "Safety Stop: Voltage limit exceeded";
    debug.chargeMode = "Safety Stop (Overvoltage)";
} else if (TotalMPPTOutput < 2000) {
    reservedPowerLimit = 18000;
    debug.mainLogicBranch = "Priority Charge: Low generation";
    debug.chargeMode = "Priority Charge";
} else if (ForecasterBufferkWh < 0) {
    reservedPowerLimit = 0;
    debug.mainLogicBranch = "Safety Stop: Error in buffer calculation";
    debug.chargeMode = "Safety Stop (Buffer Error)";
}
else if (!effectiveDayIsSunny) {
    debug.mainLogicBranch = "Entering Cloudy Day Logic";
    if (SOC >= 99 && currentHour < afternoonStartHour) {
        reservedPowerLimit = 0;
        debug.chargeMode = "Cloudy: Export (SOC 99%)";
    } else {
        reservedPowerLimit = 18000;
        debug.chargeMode = "Cloudy: Charging";
    }
}
else if (effectiveDayIsSunny) {
    if (currentHour >= EARLY_MORNING_DISCHARGE_START_HOUR && currentHour < EARLY_MORNING_DISCHARGE_END_HOUR) {
        if (SOC > targetDischargeSOC) {
            reservedPowerLimit = 0;
            earlyMorningDischargeActive = true;
            debug.mainLogicBranch = "Morning Discharge (Discharging)";
            debug.chargeMode = "Morning Discharge";
        } else {
            reservedPowerLimit = 18000;
            debug.mainLogicBranch = "Morning Discharge (Charging)";
            debug.chargeMode = "Morning Charging";
        }
    }
    else if (currentHour >= SUNRISE_GENERATION_STARTS_HOUR) {
        if (SOC >= 99 && currentHour < afternoonStartHour) {
            reservedPowerLimit = 0;
            debug.mainLogicBranch = "Hard Ceiling: SOC at 99% before final charge";
            debug.chargeMode = "Hard Ceiling 99% (Exporting)";
        }
        else if (currentHour >= afternoonStartHour && currentHour < sunsetHour) {
            var finalChargeTarget = 99;
            var chargeReason = "Soft-landing to 99%";

            // [1.7.8] shadowCorrection naudoja avgCorrectionFactor
            var dynamicShadow = (flow.get("SolarTodayRemaining") || 0) * (1 - avgCorrectionFactor);
            var shadowCorrection = Math.max(5, dynamicShadow);
            var solarTodayRemaining = Math.max(0, (flow.get("SolarTodayRemaining") || 0) - shadowCorrection);

            var proactiveThreshold = Math.max(2, BattPot * 2);
            if (solarTodayRemaining < proactiveThreshold && netEnergyForecast_18_19_Wh < 1000) {
                finalChargeTarget = 100;
                chargeReason = "Proactive MAX CHARGE (Remaining: " + solarTodayRemaining.toFixed(1) + "kWh, Threshold: " + proactiveThreshold.toFixed(1) + "kWh)";
            }
            else if (solarTodayRemaining > 0) {
                var hoursToSunset = Math.max(0, sunsetHour - currentHour);
                var avgConsumptionKWh = (flow.get("DynamicAverageConsumptionW") || 1500) / 1000;
                var consumptionUntilSunset = hoursToSunset * avgConsumptionKWh;
                var netSolarRemaining = Math.max(0, solarTodayRemaining - consumptionUntilSunset);
                if (netSolarRemaining < BattPot * 1.2) {
                    finalChargeTarget = 100;
                    chargeReason = "MAX CHARGE (Net: " + netSolarRemaining.toFixed(1) + "kWh < BattPotû1.2: " + (BattPot * 1.2).toFixed(1) + "kWh)";
                }
                if (finalChargeTarget === 99 && isCloudyTomorrow) {
                    finalChargeTarget = 100;
                    chargeReason = "MAX CHARGE (Cloudy Tomorrow)";
                }
                if (finalChargeTarget === 99 && dayOfWeekNow === 0 && !saturdayBalanceDone) {
                    finalChargeTarget = 100;
                    chargeReason = "BALANCE CHARGE (Saturday missed)";
                }
                if (finalChargeTarget === 99 && dayOfWeekNow === 0 && saturdayBalanceDone) {
                    chargeReason = "Standard 99% (Saturday balanced)";
                }
            }
            else if (isCloudyTomorrow) {
                finalChargeTarget = 100;
                chargeReason = "MAX CHARGE (Cloudy Tomorrow)";
            }
            else if (dayOfWeekNow === 0 && !saturdayBalanceDone) {
                finalChargeTarget = 100;
                chargeReason = "BALANCE CHARGE (Saturday missed)";
            }
            else if (dayOfWeekNow === 0 && saturdayBalanceDone) {
                chargeReason = "Standard 99% (Saturday balanced)";
            }

            debug.mainLogicBranch = "Entering Final Charge (" + chargeReason + ")";
            debug.activeTargetSOC = finalChargeTarget;

            if (SOC < finalChargeTarget) {
                reservedPowerLimit = 18000;
                debug.chargeMode = "Aggressive Final Charge";
            } else {
                debug.chargeMode = "Target Met or Exceeded";
                reservedPowerLimit = 0;
            }
        }
        else if (currentHour >= 14 && currentHour < afternoonStartHour) {
            if (ForecasterBufferkWh > 3) {
                debug.mainLogicBranch = "Entering Sunny 14-" + afternoonStartHour + "h block (Buffer Management)";
                if (adjustedBuffer > BattPot) {
                    reservedPowerLimit = 0;
                    debug.chargeMode = "14h Buffer: Exporting (Buffer > BattPot)";
                } else {
                    if (SOC >= 99 && dayOfWeekNow !== 0) {
                        reservedPowerLimit = 0;
                        debug.mainLogicBranch = "Sunny 14-" + afternoonStartHour + "h: Hard Ceiling 99% (Buffer)";
                        debug.chargeMode = "14h Buffer: Hard Ceiling 99%";
                    } else {
                        reservedPowerLimit = 18000;
                        debug.chargeMode = "14h Buffer: Charging";
                    }
                }
            } else {
                debug.mainLogicBranch = "Entering Sunny 14-" + afternoonStartHour + "h block (Targeting)";
                var maxDaySOC = (dayOfWeekNow === 0) ? 100 : 99;
                // 14h Targeting naudoja momentiná₤ correctionFactor
                var targetSOC = Math.min((correctionFactor <= 0.5) ? 95 : targetSOC_at_16, maxDaySOC);
                debug.activeTargetSOC = targetSOC;
                if (SOC < targetSOC) {
                    var targetEnergy_kWh = (targetSOC / 100) * TOTAL_BATTERY_CAPACITY_KWH;
                    var currentEnergy_kWh = (SOC / 100) * TOTAL_BATTERY_CAPACITY_KWH;
                    var energyNeeded_kWh = Math.max(0, targetEnergy_kWh - currentEnergy_kWh);
                    var hoursRemaining = afternoonStartHour - (currentHour + currentMinutes / 60);
                    var requiredChargePower_W = 18000;
                    if (hoursRemaining > 0.01) {
                        requiredChargePower_W = (energyNeeded_kWh / hoursRemaining) * 1000;
                    }
                    reservedPowerLimit = requiredChargePower_W * CHARGE_AGGRESSIVENESS_FACTOR;
                    debug.chargeMode = "14h Targeting: Charging to " + targetSOC + "%";
                } else {
                    reservedPowerLimit = 0;
                    debug.chargeMode = "14h Targeting: Target Met (Exporting)";
                }
            }
        }
        else if (currentHour >= SUNRISE_GENERATION_STARTS_HOUR && currentHour < 14) {
            if (ForecasterBufferkWh <= 3) {
                debug.mainLogicBranch = "Entering Sunny 9-14h block (Targeting " + targetSOC_at_14 + "%)";
                var targetSOC14 = Math.min(targetSOC_at_14, 99);
                debug.activeTargetSOC = targetSOC14;
                if (SOC < targetSOC14) {
                    var tE14 = (targetSOC14 / 100) * TOTAL_BATTERY_CAPACITY_KWH;
                    var cE14 = (SOC / 100) * TOTAL_BATTERY_CAPACITY_KWH;
                    var eN14 = Math.max(0, tE14 - cE14);
                    var hR14 = 14 - (currentHour + currentMinutes / 60);
                    var rCP14 = 18000;
                    if (hR14 > 0.01) {
                        rCP14 = (eN14 / hR14) * 1000;
                    }
                    reservedPowerLimit = rCP14;
                    debug.chargeMode = "9-14h: Charging to " + targetSOC14 + "%";
                } else {
                    reservedPowerLimit = 0;
                    debug.chargeMode = "9-14h: Target Met (Exporting)";
                }
            } else {
                debug.mainLogicBranch = "Entering Sunny 9-14h block (Buffer Management)";
                if (isCloudyTomorrow) {
                    reservedPowerLimit = 18000;
                    debug.chargeMode = "9-14h Buffer: Charging (Cloudy Tomorrow)";
                } else {
                    if (adjustedBuffer > BattPot) {
                        reservedPowerLimit = 0;
                        debug.chargeMode = "9-14h Buffer: Exporting (Buffer > BattPot)";
                    } else if (adjustedBuffer < BattPot) {
                        reservedPowerLimit = 18000;
                        debug.chargeMode = "9-14h Buffer: Charging (BattPot > Buffer)";
                    } else {
                        var hR9 = 14 - (currentHour + currentMinutes / 60);
                        if (hR9 > 0.01) {
                            var bCP9 = (BattPot / hR9) * 1000;
                            reservedPowerLimit = Math.min(bCP9, MAX_BATTERY_CHARGE_RATE_DURING_PEAK_ADJUSTABLE_BY_FORECAST);
                        } else {
                            reservedPowerLimit = 18000;
                        }
                        debug.chargeMode = "9-14h Buffer: Balanced Charging";
                    }
                }
            }
        }
        else {
            debug.mainLogicBranch = "After Sunset (Post " + sunsetHour + "h)";
            var finalChargeTargetSunset = 100;
            debug.activeTargetSOC = finalChargeTargetSunset;
            if (SOC < finalChargeTargetSunset) {
                reservedPowerLimit = 18000;
                debug.chargeMode = "Night Charge to 100%";
            } else {
                reservedPowerLimit = 0;
                debug.chargeMode = "Night: Full (100%)";
            }
        }
    }
    else {
        debug.mainLogicBranch = "Before Sunrise (Pre 6h)";
        reservedPowerLimit = 0;
        debug.chargeMode = "Pre-Sunrise (Idle)";
    }
}

// === Galutinis eksporto skaiáiavimas ===
if (!earlyMorningDischargeActive) {
    var excessPower = actualMomentarySurplus - reservedPowerLimit;
    excessPower = Math.max(0, excessPower);
    exportAmount = Math.min(excessPower, GLimit);
} else {
    exportAmount = TARGET_EXPORT_POWER_DURING_MORNING_DISCHARGE;
}

if (exportAmount > 0 && exportAmount < MINIMUM_EXPORT_THRESHOLD_W) {
    exportAmount = 0;
}

// [1.7.0] Absorpcijos fazás á₤jungimas
var generationSurplus = TotalMPPTOutput - ACC;
var lowSurplus = (generationSurplus < ABSORPTION_SURPLUS_THRESHOLD_W);
var nearSunset = (currentHour >= (sunsetHour - 1));
debug.absorptionSurplus = Math.round(generationSurplus);
debug.absorptionLowSurplus = lowSurplus;
debug.absorptionNearSunset = nearSunset;

if (SOC >= 100 && !absorptionActive && (lowSurplus || nearSunset)) {
    node.warn("Pradedama absorbcijos fazá. Surplus: " + Math.round(generationSurplus) + "W, nearSunset: " + nearSunset);
    flow.set("absorptionPhaseActive", true);
    var endTime = nowMs + (ABSORPTION_DURATION_HOURS * 60 * 60 * 1000);
    flow.set("absorptionEndTime", endTime);
    reservedPowerLimit = 18000;
    exportAmount = 0;
    debug.chargeMode = "Absorption (Just Started)";

    if (dayOfWeekNow === 6) {
        flow.set("saturdayBalanceDone", true);
        saturdayBalanceDone = true;
        node.warn("é eéÀtadienio balansavimas á₤vyko ã sekmadienis taikys standartiná 99% logiká");
    }
}

// === Pabaiga ===
debug.exportAmount = exportAmount;
debug.reservedPowerLimitFinal = reservedPowerLimit;
debug.isSunnyDayDetermined = isSunnyDayDetermined;

msg1.payload = exportAmount > 0 ? -1 * exportAmount : 0;
msg1.debug = debug;

flow.set("setpoint", exportAmount);
flow.set("debug_export", debug);
flow.set("reservedPowerLimit", reservedPowerLimit);

return msg1;

// Energetikos valdymo modulis - IéÀgauti ir Apskaiáiuoti Piko Buferá₤
// Versija 1.4.0 (su suvienodintu klaidé° apdorojimu)

// === 1. áÛRAé éý Ié GAVIMAS Ié  API ATSAKYMO ===
let payload = msg.payload;
let records = [];

if (payload && typeof payload === 'object') {
    if (payload.records && Array.isArray(payload.records.solar_yield_forecast)) {
        records = payload.records.solar_yield_forecast;
    } else if (payload.records && Array.isArray(payload.records.total_solar_yield)) {
        records = payload.records.total_solar_yield;
    } else if (payload.result && Array.isArray(payload.result.records)) {
        records = payload.result.records;
    } else if (payload.result && payload.result.records && Array.isArray(payload.result.records.solar_yield_forecast)) {
        records = payload.result.records.solar_yield_forecast;
    } else if (payload.result && payload.result.records && Array.isArray(payload.result.records.total_solar_yield)) {
        records = payload.result.records.total_solar_yield;
    }
}

// === 2. BUFERIO SKAIáIAVIMAS ===
const GRID_EXPORT_LIMIT_W = flow.get("GLimit") || 13600;
const AVERAGE_CONSUMPTION_W = flow.get("DynamicAverageConsumptionW") || 1000;
const THRESHOLD_W = GRID_EXPORT_LIMIT_W + AVERAGE_CONSUMPTION_W;
const MAX_SYSTEM_CAPACITY_W = 19200;

let forecastData = records;
let ForecasterBufferkWh = 0; // Numatytoji reikéÀmá dabar visada 0
let hasInvalidData = false;

if (!Array.isArray(forecastData) || forecastData.length === 0) {
    node.error("Calculate Peak Excess Buffer: Prognozás duomenys netinkami arba jé° nára. Buferis nustatomas á₤ 0.");
    // Klaidos atveju paliekame ForecasterBufferkWh = 0 ir baigiame darbá

} else {
    const nowUtc = new Date();
    const currentDayUtc = nowUtc.getUTCDate();
    const currentMonthUtc = nowUtc.getUTCMonth();
    const currentYearUtc = nowUtc.getUTCFullYear();
    const currentHourUtc = nowUtc.getUTCHours();

    let totalExcess = 0;

    for (let i = 0; i < forecastData.length; i++) {
        if (!Array.isArray(forecastData[i]) || forecastData[i].length < 2) continue;

        const timestamp = forecastData[i][0];
        const valueWh = forecastData[i][1];
        const forecastedPowerW = valueWh;

        if (forecastedPowerW > MAX_SYSTEM_CAPACITY_W) {
            hasInvalidData = true;
            break;
        }

        const forecastDate = new Date(timestamp);
        const forecastHourUtc = forecastDate.getUTCHours();
        const forecastDayUtc = forecastDate.getUTCDate();
        const forecastMonthUtc = forecastDate.getUTCMonth();
        const forecastYearUtc = forecastDate.getUTCFullYear();

        if (forecastDayUtc === currentDayUtc &&
            forecastMonthUtc === currentMonthUtc &&
            forecastYearUtc === currentYearUtc &&
            forecastHourUtc >= currentHourUtc) {

            if (forecastedPowerW > THRESHOLD_W) {
                const excessW = forecastedPowerW - THRESHOLD_W;
                const excessKWh = excessW / 1000;
                totalExcess += excessKWh;
            }
        }
    }

    // Nustatome galutiná reikéÀmá pagal sálygas
    if (hasInvalidData) {
        node.warn("Prognozás duomenyse rasta nereali reikéÀmá. Buferis nustatomas á₤ 0.");
        ForecasterBufferkWh = 0; // Vietoj '2' gráéƒiname 0
    } else {
        ForecasterBufferkWh = totalExcess; // Gráéƒiname apskaiáiuotá reikéÀmá (gali bé¨ti ir 0)
    }
}

// Suvienodiname visus maéƒus ar neigiamus rezultatus iki 0
if (ForecasterBufferkWh < 0.1) {
    ForecasterBufferkWh = 0;
}

flow.set("ForecasterBufferkWh", ForecasterBufferkWh);
msg.payload = ForecasterBufferkWh;
return msg;

// Energetikos valdymo modulis - Apskaiáiuoti Dinaminius SOC Tikslus
// Versija 2.7
// Pakeitimai nuo 2.6:
// 1. Pridátas exceedsGLimit patikrinimas ã ar likusios dienos valandos viréÀija GLimit
//    - Jei ne ã targetSOC_at_14 = 99%, targetSOC_at_16 = 99% (krauti maksimaliai)
//    - Jei taip ã dabartiná buferio logika iéÀlieka (reikia vietos GLimit pertekliui)
//    - Tikrinamos tik LIKUSIOS valandos (nuo currentHour iki sunsetHour)

// === 1. DUOMENéý GAVIMAS ===
const solarForecast = flow.get("solarForecast") || [];
const consumptionForecast = flow.get("consumptionForecast") || [];
const TOTAL_BATTERY_CAPACITY_KWH = 72.28;
const MINIMUM_TARGET_SOC = 85;
const afternoonForecastCorrection = flow.get("afternoonForecastCorrection") || 1;
const SolarTotalForecastToday = flow.get("SolarTotalForecastToday") || 0;
const GLimit = flow.get("GLimit") || 13600;
const dynamicSunsetHour = flow.get("dynamicSunsetHour") || 18;
const currentHour = new Date().getHours();

if (solarForecast.length === 0 || consumptionForecast.length === 0) {
    node.error("Tré¨ksta prognozié° dinaminiams SOC tikslams apskaiáiuoti.");
    flow.set("targetSOC_at_14", 90);
    flow.set("targetSOC_at_16", 95);
    flow.set("netEnergyForecast_17_18_Wh", 9999);
    flow.set("netEnergyForecast_18_19_Wh", 9999);
    return;
}

// === 2. DUOMENéý APDOROJIMAS ===
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);

let hourlySolar = {};
let hourlyConsumption = {};

for (const rec of solarForecast) {
    const recDate = new Date(rec[0]);
    if (recDate >= todayStart && recDate <= todayEnd) {
        hourlySolar[recDate.getHours()] = rec[1];
    }
}
for (const rec of consumptionForecast) {
    const recDate = new Date(rec[0]);
    if (recDate >= todayStart && recDate <= todayEnd) {
        hourlyConsumption[recDate.getHours()] = rec[1];
    }
}

function getNetEnergyWh(hour) {
    const solar = hourlySolar[hour] || 0;
    const consumption = hourlyConsumption[hour] || 0;
    return solar - consumption;
}

// === 3. GLIMIT PATIKRINIMAS ã ar likusios valandos viréÀija GLimit? ===
var startCheckHour = Math.max(13, currentHour);
var maxAfternoonW = 0;
for (var h = startCheckHour; h < dynamicSunsetHour; h++) {
    var hw = hourlySolar[h] || 0;
    if (hw > maxAfternoonW) maxAfternoonW = hw;
}
var exceedsGLimit = (maxAfternoonW > GLimit);

// === 4. TIKSLéý SKAIáIAVIMAS ===
var targetSOC_at_14;
var targetSOC_at_16;

if (!exceedsGLimit) {
    // Generacija nepasiekia GLimit ã nereikia buferio, krauti kiek galima
    targetSOC_at_14 = 99;
    targetSOC_at_16 = 99;
} else {
    // Generacija viréÀija GLimit ã reikia buferio, dabartiná logika
    const netEnergy_16_18_Wh = getNetEnergyWh(16) + getNetEnergyWh(17);
    const corrected_netEnergy_16_18_Wh = netEnergy_16_18_Wh * afternoonForecastCorrection;
    const socToFill_16_18_percent = ((corrected_netEnergy_16_18_Wh / 1000) / TOTAL_BATTERY_CAPACITY_KWH) * 100;
    targetSOC_at_16 = 100 - socToFill_16_18_percent;

    const netEnergy_14_16_Wh = getNetEnergyWh(14) + getNetEnergyWh(15);
    const totalNetEnergy_from_14h_Wh = netEnergy_14_16_Wh + corrected_netEnergy_16_18_Wh;
    const socToFill_from_14h_percent = ((totalNetEnergy_from_14h_Wh / 1000) / TOTAL_BATTERY_CAPACITY_KWH) * 100;
    targetSOC_at_14 = 100 - socToFill_from_14h_percent;

    const HIGH_PRODUCTION_DAY_KWH = 60;
    if (SolarTotalForecastToday > HIGH_PRODUCTION_DAY_KWH) {
        targetSOC_at_14 = Math.max(targetSOC_at_14, 92);
        targetSOC_at_16 = Math.max(targetSOC_at_16, 96);
    }

    targetSOC_at_16 = Math.min(100, Math.max(MINIMUM_TARGET_SOC, targetSOC_at_16));
    targetSOC_at_14 = Math.min(100, Math.max(MINIMUM_TARGET_SOC, targetSOC_at_14));
}

// === 5. REZULTATéý Ié SAUGOJIMAS ===
const uncorrected_targetSOC_at_16 = 100 - (getNetEnergyWh(16) + getNetEnergyWh(17)) / 1000 / TOTAL_BATTERY_CAPACITY_KWH * 100;

flow.set("targetSOC_at_16", Math.round(targetSOC_at_16));
flow.set("targetSOC_at_14", Math.round(targetSOC_at_14));
flow.set("netEnergyForecast_17_18_Wh", getNetEnergyWh(17));
flow.set("netEnergyForecast_18_19_Wh", getNetEnergyWh(18));

msg.payload = {
    targetSOC_at_14: Math.round(targetSOC_at_14),
    targetSOC_at_16: Math.round(targetSOC_at_16),
    uncorrected_targetSOC_at_16: Math.round(uncorrected_targetSOC_at_16),
    correctionUsed: afternoonForecastCorrection,
    exceedsGLimit: exceedsGLimit,
    maxAfternoonW: Math.round(maxAfternoonW),
    checkedFromHour: startCheckHour,
    netEnergyForecast_17_18_Wh: getNetEnergyWh(17).toFixed(2),
    netEnergyForecast_18_19_Wh: getNetEnergyWh(18).toFixed(2)
};
return msg;

// Energetikos valdymo modulis - Universalus Prognozás áÛraéÀé° IéÀgavimas
// Versija 2.1 - Atsparesnis netikátiems API atsakymams

let payload = msg.payload;
let records = [];

// Patikriname, ar gautas atsakymas yra tinkamas objektas
if (payload && typeof payload === 'object' && payload.records) {
    // Tikriname visus galimus kelius ir ar reikéÀmá yra masyvas
    if (Array.isArray(payload.records.solar_yield_forecast)) {
        records = payload.records.solar_yield_forecast;
    } 
    else if (Array.isArray(payload.records.total_solar_yield)) {
        records = payload.records.total_solar_yield;
    }
    else if (Array.isArray(payload.records.vrm_consumption_fc)) {
        records = payload.records.vrm_consumption_fc;
    }
}

// Galutinis patikrinimas (dabar tikriname tik `records` kintamájá₤)
if (records.length === 0) {
    node.warn("Universal Extract Records: Duomené° masyvo nepavyko rasti arba jis tuéÀáias. Patikrinkite API atsakymá:", msg.payload);
    msg.payload = [];
} else {
    msg.payload = records;
}

return msg;

// Energetikos valdymo modulis - Apskaiáiuoti Dinaminius SOC Tikslus
// Versija 2.7
// Pakeitimai nuo 2.6:
// 1. Pridátas exceedsGLimit patikrinimas ã ar likusios dienos valandos viréÀija GLimit
//    - Jei ne ã targetSOC_at_14 = 99%, targetSOC_at_16 = 99% (krauti maksimaliai)
//    - Jei taip ã dabartiná buferio logika iéÀlieka (reikia vietos GLimit pertekliui)
//    - Tikrinamos tik LIKUSIOS valandos (nuo currentHour iki sunsetHour)

// === 1. DUOMENéý GAVIMAS ===
const solarForecast = flow.get("solarForecast") || [];
const consumptionForecast = flow.get("consumptionForecast") || [];
const TOTAL_BATTERY_CAPACITY_KWH = 72.28;
const MINIMUM_TARGET_SOC = 85;
const afternoonForecastCorrection = flow.get("afternoonForecastCorrection") || 1;
const SolarTotalForecastToday = flow.get("SolarTotalForecastToday") || 0;
const GLimit = flow.get("GLimit") || 13600;
const dynamicSunsetHour = flow.get("dynamicSunsetHour") || 18;
const currentHour = new Date().getHours();

if (solarForecast.length === 0 || consumptionForecast.length === 0) {
    node.error("Tré¨ksta prognozié° dinaminiams SOC tikslams apskaiáiuoti.");
    flow.set("targetSOC_at_14", 90);
    flow.set("targetSOC_at_16", 95);
    flow.set("netEnergyForecast_17_18_Wh", 9999);
    flow.set("netEnergyForecast_18_19_Wh", 9999);
    return;
}

// === 2. DUOMENéý APDOROJIMAS ===
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);

let hourlySolar = {};
let hourlyConsumption = {};

for (const rec of solarForecast) {
    const recDate = new Date(rec[0]);
    if (recDate >= todayStart && recDate <= todayEnd) {
        hourlySolar[recDate.getHours()] = rec[1];
    }
}
for (const rec of consumptionForecast) {
    const recDate = new Date(rec[0]);
    if (recDate >= todayStart && recDate <= todayEnd) {
        hourlyConsumption[recDate.getHours()] = rec[1];
    }
}

function getNetEnergyWh(hour) {
    const solar = hourlySolar[hour] || 0;
    const consumption = hourlyConsumption[hour] || 0;
    return solar - consumption;
}

// === 3. GLIMIT PATIKRINIMAS ã ar likusios valandos viréÀija GLimit? ===
var startCheckHour = Math.max(13, currentHour);
var maxAfternoonW = 0;
for (var h = startCheckHour; h < dynamicSunsetHour; h++) {
    var hw = hourlySolar[h] || 0;
    if (hw > maxAfternoonW) maxAfternoonW = hw;
}
var exceedsGLimit = (maxAfternoonW > GLimit);

// === 4. TIKSLéý SKAIáIAVIMAS ===
var targetSOC_at_14;
var targetSOC_at_16;

if (!exceedsGLimit) {
    // Generacija nepasiekia GLimit ã nereikia buferio, krauti kiek galima
    targetSOC_at_14 = 99;
    targetSOC_at_16 = 99;
} else {
    // Generacija viréÀija GLimit ã reikia buferio, dabartiná logika
    const netEnergy_16_18_Wh = getNetEnergyWh(16) + getNetEnergyWh(17);
    const corrected_netEnergy_16_18_Wh = netEnergy_16_18_Wh * afternoonForecastCorrection;
    const socToFill_16_18_percent = ((corrected_netEnergy_16_18_Wh / 1000) / TOTAL_BATTERY_CAPACITY_KWH) * 100;
    targetSOC_at_16 = 100 - socToFill_16_18_percent;

    const netEnergy_14_16_Wh = getNetEnergyWh(14) + getNetEnergyWh(15);
    const totalNetEnergy_from_14h_Wh = netEnergy_14_16_Wh + corrected_netEnergy_16_18_Wh;
    const socToFill_from_14h_percent = ((totalNetEnergy_from_14h_Wh / 1000) / TOTAL_BATTERY_CAPACITY_KWH) * 100;
    targetSOC_at_14 = 100 - socToFill_from_14h_percent;

    const HIGH_PRODUCTION_DAY_KWH = 60;
    if (SolarTotalForecastToday > HIGH_PRODUCTION_DAY_KWH) {
        targetSOC_at_14 = Math.max(targetSOC_at_14, 92);
        targetSOC_at_16 = Math.max(targetSOC_at_16, 96);
    }

    targetSOC_at_16 = Math.min(100, Math.max(MINIMUM_TARGET_SOC, targetSOC_at_16));
    targetSOC_at_14 = Math.min(100, Math.max(MINIMUM_TARGET_SOC, targetSOC_at_14));
}

// === 5. REZULTATéý Ié SAUGOJIMAS ===
const uncorrected_targetSOC_at_16 = 100 - (getNetEnergyWh(16) + getNetEnergyWh(17)) / 1000 / TOTAL_BATTERY_CAPACITY_KWH * 100;

flow.set("targetSOC_at_16", Math.round(targetSOC_at_16));
flow.set("targetSOC_at_14", Math.round(targetSOC_at_14));
flow.set("netEnergyForecast_17_18_Wh", getNetEnergyWh(17));
flow.set("netEnergyForecast_18_19_Wh", getNetEnergyWh(18));

msg.payload = {
    targetSOC_at_14: Math.round(targetSOC_at_14),
    targetSOC_at_16: Math.round(targetSOC_at_16),
    uncorrected_targetSOC_at_16: Math.round(uncorrected_targetSOC_at_16),
    correctionUsed: afternoonForecastCorrection,
    exceedsGLimit: exceedsGLimit,
    maxAfternoonW: Math.round(maxAfternoonW),
    checkedFromHour: startCheckHour,
    netEnergyForecast_17_18_Wh: getNetEnergyWh(17).toFixed(2),
    netEnergyForecast_18_19_Wh: getNetEnergyWh(18).toFixed(2)
};
return msg;

// Energetikos valdymo modulis - Universalus Prognozás áÛraéÀé° IéÀgavimas
// Versija 2.1 - Atsparesnis netikátiems API atsakymams

let payload = msg.payload;
let records = [];

// Patikriname, ar gautas atsakymas yra tinkamas objektas
if (payload && typeof payload === 'object' && payload.records) {
    // Tikriname visus galimus kelius ir ar reikéÀmá yra masyvas
    if (Array.isArray(payload.records.solar_yield_forecast)) {
