if (last14DaysRecords.length === 0) {
    node.error("Per paskutines 14 diené° nerasta istorinié° duomené°.");
    flow.set("dynamicDayThreshold", 40);
    return;
}

// Toliau viská skaiáiuojame naudodami jau filtruotá masyvá
const dailyTotals_kWh = last14DaysRecords.map(record => record[1]);

// Randame geriausiá rezultatá per paskutines 14 diené°
const bestRecentDay_kWh = Math.max(...dailyTotals_kWh);

// Apskaiáiuojame dinaminá ribá (pvz., 50% geriausio rezultato)
const dynamicThreshold_kWh = bestRecentDay_kWh * 0.50;

// IéÀsaugome reikéÀmá, kad "Atidavimas" modulis galáté° já naudoti
flow.set("dynamicDayThreshold", dynamicThreshold_kWh);

// ParuoéÀiame iéÀvestá₤ patogiam debug'inimui
msg.payload = `Apskaiáiuota dinaminá riba: ${dynamicThreshold_kWh.toFixed(2)} kWh (pagal geriausiá ${bestRecentDay_kWh.toFixed(2)} kWh rezultatá per 14d.)`;
return msg;

// Energetikos valdymo modulis - Popietás Prognozatorius (Konservatyvus)
// Versija 2.0

// Gauname istorijos duomenis iéÀ failo, kuris buvo nuskaitytas ankstesniame mazge
const historyJson = msg.payload;
let history = [];
// Nustatome saugiá numatytájá reikéÀmá 1.0 (jokios korekcijos), kuri bus naudojama, jei istorija tuéÀáia.
let predictedFactor = 1.0; 

try {
    // Bandome konvertuoti tekstá (JSON string) á₤ duomené° masyvá
    history = JSON.parse(historyJson);
} catch (e) {
    // Jei failas tuéÀáias ar sugadintas, JSON.parse nepavyks.
    // IéÀvedame á₤spájimá ir paliekame history = [], o predictedFactor = 1.0.
    node.warn("Istorijos failas tuéÀáias arba netinkamo formato.");
}

// Patikriname, ar pavyko gauti duomené° masyvá ir ar jis nára tuéÀáias.
if (Array.isArray(history) && history.length > 0) {
    // Pasiimame patá₤ naujausiá (vakarykéÀtá₤) á₤raéÀá.
    const yesterdayRecord = history[history.length - 1];

    // Tikriname, ar vakarykéÀtá diena buvo PRastesná nei prognozuota (avg_factor < 1.0).
    // Mes "mokomás" tik iéÀ blogé° diené°, kad bé¨tume konservatyvé¨s.
    if (yesterdayRecord && typeof yesterdayRecord.avg_factor === 'number' && yesterdayRecord.avg_factor < 1.0) {

        if (history.length === 1) {
            // Jei istorijoje yra tik viena (prasta) diena, jos rezultatá ir naudojame kaip prognozá.
            predictedFactor = yesterdayRecord.avg_factor;
        } else {
            // Jei istorijoje yra dvi ar daugiau diené°, imam paskutines dvi.
            const dayBeforeRecord = history[history.length - 2];
            if (dayBeforeRecord && typeof dayBeforeRecord.avg_factor === 'number') {
                const yesterdayFactor = yesterdayRecord.avg_factor;
                const dayBeforeFactor = dayBeforeRecord.avg_factor;

                // Skaiáiuojame svertiná₤ vidurká₤: 75% á₤takos iéÀ vakarykéÀtás dienos, 25% - iéÀ uéƒvakarykéÀtás.
                predictedFactor = (yesterdayFactor * 0.75) + (dayBeforeFactor * 0.25);
            }
        }
    }
    // Jei vakarykéÀtá diena buvo gera (avg_factor >= 1.0), nieko nedarome.
    // Tokiu atveju predictedFactor lieka lygus pradinei 1.0 reikéÀmei.
}

// Apribojame galutiná reikéÀmá, kad ji nebé¨té° pernelyg optimistiná (didesná uéƒ 1.0)
// ar pernelyg pesimistiéÀka (maéƒesná uéƒ 0.1).
predictedFactor = Math.min(1.0, predictedFactor); 
predictedFactor = Math.max(0.1, predictedFactor);

// IéÀsaugome apskaiáiuotá koeficientá á₤ flow "atmintá₤", kad já₤ galáté° naudoti kiti moduliai.
flow.set("afternoonForecastCorrection", predictedFactor);

// ParuoéÀiame informatyvé° praneéÀimá debug iéÀvesáiai.
msg.payload = {
    note: "Apskaiáiuotas konservatyvus popietás korekcijos faktorius.",
    predictedAfternoonFactor: parseFloat(predictedFactor.toFixed(4)),
    historyUsed: history.slice(-2)
};

return msg;

// Energetikos valdymo modulis - Korekcijos faktoriaus skaiáiavimas
// Versija 3.2 (su lanksáiu laiko palyginimu)

// --- 1. Duomené° gavimas iéÀ FLOW kintamé°jé° ---
const forecastArray = flow.get("solarForecastToday") || [];
const actualYieldArray = flow.get("actualYield") || [];
let dailyCorrectionFactors = flow.get("dailyCorrectionFactors") || Array(9).fill(1);
let correctionFactor = 1;

if (forecastArray.length === 0 || actualYieldArray.length === 0) {
    node.error("Korekcijos faktorius: Tré¨ksta prognozás arba realié° gamybos duomené°.");
    flow.set("CorrectionFactor", 1);
    return;
}

// --- 2. ReikéÀmié° apskaiáiavimas ---
const now = new Date();
const currentHour = now.getHours();
const lastHourStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), currentHour - 1, 0, 0, 0);
const lastHourEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), currentHour - 1, 59, 59, 999);
const lastHourStartTimestamp = lastHourStart.getTime();
const lastHourEndTimestamp = lastHourEnd.getTime();

let forecastedPowerLastHourWh = 0;
let actualPowerLastHourWh = 0;

// IeéÀkome prognozás praájusios valandos INTERVALE
for (const record of forecastArray) {
    if (record[0] >= lastHourStartTimestamp && record[0] <= lastHourEndTimestamp) {
        forecastedPowerLastHourWh = record[1];
        break;
    }
}

// IeéÀkome realios gamybos praájusios valandos INTERVALE
for (const record of actualYieldArray) {
    if (record[0] >= lastHourStartTimestamp && record[0] <= lastHourEndTimestamp) {
        actualPowerLastHourWh = record[1];
        break;
    }
}

// --- 3. Korekcijos faktoriaus skaiáiavimas ---
if (actualPowerLastHourWh > 0 && forecastedPowerLastHourWh > 0) {
    correctionFactor = actualPowerLastHourWh / forecastedPowerLastHourWh;
} else if (actualPowerLastHourWh > 0 && forecastedPowerLastHourWh === 0) {
    correctionFactor = 2.0;
} else {
    correctionFactor = 1;
}

correctionFactor = Math.min(correctionFactor, 2.0); 
correctionFactor = Math.max(correctionFactor, 0.1);

// --- 4. Rezultaté° iéÀsaugojimas ---
flow.set("CorrectionFactor", correctionFactor);

const index = currentHour - 1 - 9;
if (index >= 0 && index < dailyCorrectionFactors.length) {
    dailyCorrectionFactors[index] = correctionFactor;
    flow.set("dailyCorrectionFactors", dailyCorrectionFactors);
}

msg.payload = correctionFactor;
msg.debug = {
    actualPowerLastHourWh: actualPowerLastHourWh,
    forecastedPowerLastHourWh: forecastedPowerLastHourWh,
    calculatedCorrectionFactor: correctionFactor,
    updatedDailyFactors: dailyCorrectionFactors
};

return msg;

