const today = now.toISOString().split('T')[0];

// === 1. SNAPSHOT VALIDACIJA ===
const snapshotDate = flow.get("snapshotForecastDate");
if (snapshotDate !== today) {
    node.warn("Snapshot data (" + snapshotDate + ") nesutampa su siandien (" + today + "). Kaupiklis sustabdytas.");
    return null;
}

// === 2. DUOMENU SURINKIMAS ===
const vrm_p50     = flow.get("snapshotForecastVRM");
const solcast_p50 = flow.get("snapshotForecastSolcastP50");
const solcast_p10 = flow.get("snapshotForecastSolcastP10");

const actual_kwh_raw = flow.get("todayActualKWh");
var actual_kwh = null;
if (actual_kwh_raw !== null && actual_kwh_raw !== undefined) {
    actual_kwh = parseFloat(parseFloat(actual_kwh_raw).toFixed(3));
}

// === 3. VALIDACIJA ===
if (vrm_p50 === null || vrm_p50 === undefined) {
    node.warn("Kaupiklis: truksta VRM snapshot duomenu.");
    return null;
}
if (solcast_p50 === null || solcast_p50 === undefined) {
    node.warn("Kaupiklis: truksta Solcast P50 duomenu.");
    return null;
}
if (solcast_p10 === null || solcast_p10 === undefined) {
    node.warn("Kaupiklis: truksta Solcast P10 duomenu.");
    return null;
}

// === 4. IRASO SUDARYMAS ===
var vrm_error = null;
var solcast_error = null;
var solcast_p10_error = null;
if (actual_kwh !== null) {
    vrm_error          = parseFloat((vrm_p50     - actual_kwh).toFixed(2));
    solcast_error      = parseFloat((solcast_p50 - actual_kwh).toFixed(2));
    solcast_p10_error  = parseFloat((solcast_p10 - actual_kwh).toFixed(2));
}

var todayRecord = {
    date:              today,
    vrm_p50:           parseFloat(vrm_p50.toFixed(2)),
    solcast_p50:       parseFloat(solcast_p50.toFixed(2)),
    solcast_p10:       parseFloat(solcast_p10.toFixed(2)),
    actual_kwh:        actual_kwh,
    vrm_error:         vrm_error,
    solcast_error:     solcast_error,
    solcast_p10_error: solcast_p10_error
};

// === 5. ISTORIJOS ATNAUJINIMAS ===
var history = [];
try {
    history = JSON.parse(msg.payload || "[]");
} catch(e) {
    node.warn("Istorijos failas tuscias arba sugadintas. Kuriama nauja.");
}

if (!Array.isArray(history)) history = [];

var existingIdx = history.findIndex(function(r) { return r.date === today; });
if (existingIdx >= 0) {
    node.warn("Irasas " + today + " jau egzistuoja. Atnaujinamas.");
    history[existingIdx] = todayRecord;
} else {
    history.push(todayRecord);
}

// Laikyti tik paskutines 30 dienu
while (history.length > 30) history.shift();

// === 6. ISVESTIS ===
node.warn("Kaupiklis issaugojo: " + today +
    " | VRM=" + todayRecord.vrm_p50 +
    " | Solcast P50=" + todayRecord.solcast_p50 +
    " | P10=" + todayRecord.solcast_p10 +
    " | Faktine=" + todayRecord.actual_kwh +
    " | VRM klaida=" + todayRecord.vrm_error +
    " | Solcast klaida=" + todayRecord.solcast_error +
    " | P10 klaida=" + todayRecord.solcast_p10_error);

msg.payload = JSON.stringify(history, null, 2);
return msg;

// VRM gráéƒina jau kWh - nereikia dalinti iéÀ 1000
msg.payload = msg.payload.totals.total_solar_yield;
flow.set("todayActualKWh", msg.payload);
return msg;

// Ryto Prognozás Snapshot
// Versija 1.1
// Paleidéƒiamas kasdien 07:00

const today = new Date().toISOString().split('T')[0];
const existingDate = flow.get("snapshotForecastDate");

if (existingDate === today) {
    node.warn("Snapshot jau iéÀsaugotas éÀiai dienai (" + today + "), praleidéƒiama.");
    return null;
}

const vrm = flow.get("SolarTotalForecastToday");

const dailyTotal    = global.get("DailyTotal");
const dailyTotalP10 = global.get("DailyTotalP10");
const solcastP50 = (Array.isArray(dailyTotal)    && dailyTotal.length > 0)    ? dailyTotal[0]    : null;
const solcastP10 = (Array.isArray(dailyTotalP10) && dailyTotalP10.length > 0) ? dailyTotalP10[0] : null;

if (vrm === null || vrm === undefined) {
    node.warn("Snapshot: SolarTotalForecastToday dar nepasiekiamas, praleidéƒiama.");
    return null;
}

flow.set("snapshotForecastVRM",        vrm);
flow.set("snapshotForecastSolcastP50", solcastP50);
flow.set("snapshotForecastSolcastP10", solcastP10);
flow.set("snapshotForecastDate",       today);

node.warn("Snapshot iéÀsaugotas: " + today + " | VRM=" + vrm.toFixed(2) + " | Solcast P50=" + (solcastP50 ? solcastP50.toFixed(2) : "null") + " | P10=" + (solcastP10 ? solcastP10.toFixed(2) : "null"));
msg.payload = { date: today, vrm: vrm, solcastP50: solcastP50, solcastP10: solcastP10 };
return msg;

msg.payload = {
    date:         flow.get("snapshotForecastDate"),
    vrm:          flow.get("snapshotForecastVRM"),
    solcastP50:   flow.get("snapshotForecastSolcastP50"),
    solcastP10:   flow.get("snapshotForecastSolcastP10"),
    actualKwh: flow.get("todayActualKWh")
};
return msg;

// Energetikos Valdymo áÛvykié° é§urnalas (Log)
// Registruoja tik bé¨sené° pasikeitimus

// Patikriname, ar turime debug duomenis iéÀ "Atidavimas" modulio
if (!msg.debug || !msg.debug.mainLogicBranch) {
    return null;
}

const currentBranch = msg.debug.mainLogicBranch;
const lastBranch = context.get("lastBranch");

// Jei bé¨sena (logikos éÀaka) nepasikeitá, nieko nedarome (kad nespamintume failo)
if (currentBranch === lastBranch) {
    return null;
}

// IéÀsaugome naujá bé¨sená atmináiai
context.set("lastBranch", currentBranch);

// Suformuojame graéƒé° laiko formatá (pvz., 2026-03-05 06:15:22)
const now = new Date();
const timeStr = now.getFullYear() + "-" + 
    String(now.getMonth() + 1).padStart(2, '0') + "-" + 
    String(now.getDate()).padStart(2, '0') + " " + 
    String(now.getHours()).padStart(2, '0') + ":" + 
    String(now.getMinutes()).padStart(2, '0') + ":" + 
    String(now.getSeconds()).padStart(2, '0');

// IéÀtraukiame svarbiausius parametrus to momento fiksavimui
const soc = msg.debug.SOC;
const exportW = msg.debug.exportAmount;
const battW = msg.debug.BPW;
const targetSOC = msg.debug.activeTargetSOC || "-";
const mppt = msg.debug.TotalMPPTOutput;
const correction = (msg.debug.correctionFactor).toFixed(2);

// Sukuriame tekstiná eilutá, kuri bus á₤raéÀyta á₤ failá
const logLine = `[${timeStr}] Þ BéˆSENA: ${currentBranch} | SOC: ${soc}% (Tikslas: ${targetSOC}%) | MPPT: ${mppt}W | Batt: ${battW}W | Eksportas: ${exportW}W | Korekcija: ${correction}\n`;

// Perduodame tekstá á₤raéÀymui
msg.payload = logLine;

return msg;

msg.payload = flow.get("snapshotForecastDate");
msg.payload2 = global.get("forecastHistory"); // arba nuskaityti failá
return msg;

// Sezoninis 1.0.0
// Nuskaito Max Charge Current ir Minimum SOC iéÀ Victron DBUS
// Identifikuoja mazgá pagal msg.topic

var topic = msg.topic || "";
var value = msg.payload;

if (topic.indexOf("Max Charge") !== -1) {
    flow.set("maxChargeCurrent", value);
} else if (topic.indexOf("Minimum SOC") !== -1) {
    flow.set("autoMinSOC", value);
}

var maxChargeCurrent = flow.get("maxChargeCurrent") || 0;
var autoMinSOC = flow.get("autoMinSOC") || 0;

msg.payload = { maxChargeCurrent: maxChargeCurrent, autoMinSOC: autoMinSOC };
return msg;

// Solar Actual Today - faktiná gamyba nuo vidurnakáio
// Versija 1.1
// Pakeitimai: papildomai iéÀsaugomas records masyvas kaip flow.actualYield
// (naudojamas Korekcijos faktoriaus skaiáiavime)

var payload = msg.payload;
var totals = payload.totals;
var records = payload.records;

// Dashboard + Kaupiklis: bendra faktiná gamyba nuo vidurnakáio (kWh)
if (totals && totals.solar_yield !== undefined) {
    var kWh = Math.round(totals.solar_yield / 10) / 100;
    flow.set("todayActualKWh", kWh);
}

// Korekcijos faktorius: valandinis masyvas [[timestamp, kWh], ...]
if (records && Array.isArray(records.solar_yield)) {
    flow.set("actualYield", records.solar_yield);
}

return msg;

// é eéÀálio korekcijos skaiáiavimas rytojaus prognozei
// Versija 1.1.3
// Pakeitimai nuo 1.1.2:
// 1. firstHour gráéƒintas á₤ hardcoded 10 ã generacija visada prasideda ~10h dál rytinio éÀeéÀálio
//    - 1.1.2 naudojo tomorrowWithGen[0] valandá (7h) ã idx per didelis ã shadowHours = 0
//    - dailyCorrectionFactors masyvas visada prasideda nuo ~10h

var solarForecastTomorrow = flow.get("solarForecastTomorrow") || [];
var dailyCorrectionFactors = flow.get("dailyCorrectionFactorsSnapshot") || flow.get("dailyCorrectionFactors") || [];
var sunsetHour = flow.get("dynamicSunsetHour") || 18;

node.warn("Shadow debug: sunsetHour=" + sunsetHour +
    " | dailyCorrectionFactors=" + JSON.stringify(dailyCorrectionFactors) +
    " | solarForecastTomorrow count=" + solarForecastTomorrow.length);

// === Patikrinti ar diena buvo sauláta ===
var sunnyHoursCount = 0;
for (var i = 0; i < dailyCorrectionFactors.length; i++) {
    if (dailyCorrectionFactors[i] >= 1) sunnyHoursCount++;
}

var shadowCorrectionKWh = 0;
var shadowHours = [];

if (sunnyHoursCount >= 3) {
    // === Sauláta diena ã skaiáiuoti éÀeéÀálio valandas nuo vakaro ===
    var tomorrowWithGen = [];
    for (var j = 0; j < solarForecastTomorrow.length; j++) {
        if (solarForecastTomorrow[j][1] > 0) {
            tomorrowWithGen.push(solarForecastTomorrow[j]);
        }
    }

    // firstHour = 10 (hardcoded) ã generacija visada prasideda ~10h dál rytinio medéƒié° éÀeéÀálio
    var firstHour = 10;

    // Einame nuo paskutinás valandos atgal ã imame kol factor < 1
    for (var k = tomorrowWithGen.length - 1; k >= 0; k--) {
        var h = new Date(tomorrowWithGen[k][0]).getHours();
        var idx = h - firstHour;
        var f = (idx >= 0 && idx < dailyCorrectionFactors.length) ? dailyCorrectionFactors[idx] : 1;

        if (f < 1) {
            shadowHours.push({ h: h, forecastWh: tomorrowWithGen[k][1], factor: f });
        } else {
            break;
        }
    }

    // === Skaiáiuojame éÀeéÀálio nuostolá₤ ===
    for (var s = 0; s < shadowHours.length; s++) {
        var loss = (shadowHours[s].forecastWh * (1 - shadowHours[s].factor)) / 1000;
        shadowCorrectionKWh += Math.max(0, loss);
    }
} else {
    node.warn("Shadow correction: debesuota diena (sunnyHours=" + sunnyHoursCount + ") ã korekcija = 0");
}

shadowCorrectionKWh = Math.max(0, shadowCorrectionKWh);
flow.set("shadowCorrectionKWh", shadowCorrectionKWh);

node.warn("Shadow correction rytojui: " + shadowCorrectionKWh.toFixed(2) + " kWh" +
    " | sunnyHours=" + sunnyHoursCount +
    " | shadowHours=" + shadowHours.length +
    " | detalás=" + JSON.stringify(shadowHours.map(function(x) {
        return x.h + "h=" + (x.forecastWh/1000).toFixed(2) + "kWh f=" + x.factor.toFixed(2);
    })));

// === Diagnostika ===
flow.set("shadowCorrectionDiag", {
    timestamp: new Date().toISOString(),
    shadowCorrectionKWh: shadowCorrectionKWh,
    sunsetHour: sunsetHour,
    firstHour: 10,
    sunnyHoursCount: sunnyHoursCount,
    shadowHoursCount: shadowHours.length,
    shadowHours: shadowHours,
    dailyCorrectionFactorsLength: dailyCorrectionFactors.length,
    dailyCorrectionFactors: dailyCorrectionFactors,
    solarForecastTomorrowCount: solarForecastTomorrow.length
});

msg.payload = shadowCorrectionKWh;
return msg;

// Solar Actual Today - faktiná gamyba nuo vidurnakáio
// Versija 1.2
// Pakeitimai: siunáia á₤ MQTT
var payload = msg.payload;
var totals = payload.totals;
var records = payload.records;

// Dashboard + Kaupiklis: bendra faktiná gamyba nuo vidurnakáio (kWh)
if (totals && totals.solar_yield !== undefined) {
    var kWh = Math.round(totals.solar_yield / 10) / 100;
    flow.set("todayActualKWh", kWh);
}

// Korekcijos faktorius: valandinis masyvas [[timestamp, kWh], ...]
if (records && Array.isArray(records.solar_yield)) {
    flow.set("actualYield", records.solar_yield);
}

// Sié°sti á₤ MQTT
msg.topic = "homeassistant/sensor/solar_today_actual/state";
msg.payload = flow.get("todayActualKWh");
return msg;

// Dashboard MQTT Publisher
// Versija 1.2
// Pakeitimai nuo 1.1:
// 1. day_type_status ã anglé° ã lietuvié° kalba (SunnyãSauláta, CloudyãDebesuota)
// 2. is_cloudy_tomorrow ã bool ã lietuvié° kalba (Sauláta/Debesuota)
// 3. shadow_correction fallback 5ã3

var d = msg.debug;
if (!d) {
    node.warn("msg.debug neegzistuoja");
    return null;
}

var base = "homeassistant/sensor/victron_dashboard/";

function dayTypeLabel(type) {
    return type === "Sunny" ? "Sauláta" : "Debesuota";
}

var topics = [
    { t: "day_type_status",       v: d.dayTypeSwitched ? ("Persijungá: " + dayTypeLabel(d.initialDayType) + " -> " + dayTypeLabel(d.effectiveDayType)) : dayTypeLabel(d.effectiveDayType) },
    { t: "correction_factor",     v: Math.round(d.correctionFactor * 100) / 100 },
    { t: "buffer",                v: Math.round(d.adjustedBuffer * 100) / 100 },
    { t: "total_mppt_output",     v: d.TotalMPPTOutput },
    { t: "export_to_grid",        v: Math.round(d.exportAmount * 100) / 100 },
    { t: "solar_forecast_today",  v: Math.round(d.SolarTotalForecastToday * 100) / 100 },
    { t: "solar_today_remaining", v: Math.round(d.SolarTodayRemaining * 100) / 100 },
    { t: "batt_pot",              v: Math.round(d.BattPot * 100) / 100 },
    { t: "avg_consumption_w",     v: d.DynamicAverageConsumptionW },
    { t: "acc",                   v: d.ACC },
    { t: "is_cloudy_tomorrow",    v: d.isCloudyTomorrow ? "Debesuota" : "Sauláta" },
    { t: "active_target_soc",     v: d.activeTargetSOC },
    { t: "bpw",                   v: d.BPW },
    { t: "reserved_power_limit",  v: Math.round(d.reservedPowerLimitFinal) },
    { t: "dynamic_day_threshold", v: Math.round(d.dynamicDayThreshold * 100) / 100 },
    { t: "charge_mode",           v: d.chargeMode },
    { t: "main_logic_branch",     v: d.mainLogicBranch },
    { t: "solar_actual_today",    v: Math.round((flow.get("todayActualKWh") || 0) * 100) / 100 },
    { t: "shadow_correction",     v: Math.round(((function() { var s = flow.get("shadowCorrectionKWh"); return (s !== null && s !== undefined) ? s : 3; })()) * 100) / 100 }
];

var msgs = topics.map(function(item) {
    return {
        topic: base + item.t + "/state",
        payload: item.v !== undefined && item.v !== null ? item.v : "unknown",
        retain: true
    };
});

msgs.forEach(function(m) { node.send(m); });
return null;

flow.set("BMS_CCL", msg.payload);
msg.payload = msg.payload;
return msg;
